#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, P;
        scanf("%d %d", &N, &P);
        if (P == 1) {
            printf("impossible\n");
        } else {
            char str[N + 1];
            for (int i = 0; i < N / P; i++) {
                if (i % 2 == 0) {
                    strcat(str, "ab");
                } else {
                    strcat(str, "ba");
                }
            }
            printf("%s", str);
            for (int i = N / P - 1; i >= 0; i--) {
                if (i % 2 == 0) {
                    printf("ba");
                } else {
                    printf("ab");
                }
            }
            printf("\n");
        }
    }
    return 0;
}

